mkdir -p /tmp/eval_perf && printf 'def find_duplicates(items):
    """Return all values that appear more than once, in input order, each once."""
    # Currently O(n^2) — too slow for large inputs.
    seen_dupes = []
    for i, x in enumerate(items):
        if x in seen_dupes:
            continue
        for j in range(i + 1, len(items)):
            if items[j] == x:
                seen_dupes.append(x)
                break
    return seen_dupes
' > /tmp/eval_perf/dupes.py
